namespace HospitalManagementSystem.AppointmentManagement.Models;
public class Slot { public int SlotId { get; set; } public int DoctorId { get; set; } public DateTime SlotDate { get; set; } public TimeSpan StartTime { get; set; } public TimeSpan EndTime { get; set; } public bool IsBooked { get; set; } public bool IsAvailable() => !IsBooked && (SlotDate.Date > DateTime.Today || (SlotDate.Date == DateTime.Today && StartTime > DateTime.Now.TimeOfDay)); }
